import React, { useState } from "react";
import { addFood } from "../services/api";

function AddFoodPage() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [type, setType] = useState("Prepared Meal");
  const [expiry, setExpiry] = useState("");
  const [location, setLocation] = useState("");
  const [providerId, setProviderId] = useState("");
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError(null);
    setMessage(null);
    try {
      await addFood({ provider_id: providerId, title, description, quantity, type, expiry, location });
      setMessage("Food item listed successfully.");
      setTitle("");
      setDescription("");
      setQuantity(1);
      setExpiry("");
      setLocation("");
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div className="max-w-3xl mx-auto px-6 lg:px-12 py-12">
      <div className="mb-12">
        <h2 className="text-5xl font-black text-gray-900 mb-4 tracking-tight">List Surplus Food</h2>
        <p className="text-gray-500 text-lg font-medium">Quickly post available items for NGOs to claim.</p>
      </div>

      <div className="bg-white p-12 rounded-[3rem] border border-gray-100 shadow-xl shadow-gray-200/40">
        {message && <div className="p-4 mb-8 bg-emerald-50 border border-emerald-100 rounded-2xl text-primary text-sm font-bold">{message}</div>}
        {error && <div className="p-4 mb-8 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-sm font-bold">{error}</div>}
        
        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="form-group">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Provider ID</label>
              <input 
                value={providerId} 
                onChange={(e) => setProviderId(e.target.value)} 
                required 
                className="w-full bg-gray-50 border-none rounded-2xl py-4 px-6 text-gray-900 font-medium placeholder:text-gray-300 focus:ring-2 focus:ring-primary/20 transition-all"
              />
            </div>
            <div className="form-group">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Food Title</label>
              <input 
                value={title} 
                onChange={(e) => setTitle(e.target.value)} 
                required 
                className="w-full bg-gray-50 border-none rounded-2xl py-4 px-6 text-gray-900 font-medium placeholder:text-gray-300 focus:ring-2 focus:ring-primary/20 transition-all"
                placeholder="e.g. Leftover Biryani"
              />
            </div>
          </div>

          <div className="form-group">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Description</label>
            <textarea 
              value={description} 
              onChange={(e) => setDescription(e.target.value)} 
              rows="4" 
              required 
              className="w-full bg-gray-50 border-none rounded-2xl py-4 px-6 text-gray-900 font-medium placeholder:text-gray-300 focus:ring-2 focus:ring-primary/20 transition-all"
              placeholder="Provide details about the food, condition, and packaging..."
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="form-group">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Quantity (Servings)</label>
              <input 
                value={quantity} 
                onChange={(e) => setQuantity(Number(e.target.value))} 
                type="number" 
                min="1" 
                required 
                className="w-full bg-gray-50 border-none rounded-2xl py-4 px-6 text-gray-900 font-medium placeholder:text-gray-300 focus:ring-2 focus:ring-primary/20 transition-all"
              />
            </div>
            <div className="form-group">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Food Type</label>
              <input 
                value={type} 
                onChange={(e) => setType(e.target.value)} 
                required 
                className="w-full bg-gray-50 border-none rounded-2xl py-4 px-6 text-gray-900 font-medium placeholder:text-gray-300 focus:ring-2 focus:ring-primary/20 transition-all"
                placeholder="Veg / Non-Veg / Bakery"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="form-group">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Expiry Date & Time</label>
              <input 
                value={expiry} 
                onChange={(e) => setExpiry(e.target.value)} 
                type="datetime-local" 
                required 
                className="w-full bg-gray-50 border-none rounded-2xl py-4 px-6 text-gray-900 font-medium placeholder:text-gray-300 focus:ring-2 focus:ring-primary/20 transition-all"
              />
            </div>
            <div className="form-group">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Pickup Location</label>
              <input 
                value={location} 
                onChange={(e) => setLocation(e.target.value)} 
                required 
                className="w-full bg-gray-50 border-none rounded-2xl py-4 px-6 text-gray-900 font-medium placeholder:text-gray-300 focus:ring-2 focus:ring-primary/20 transition-all"
                placeholder="Full address or area"
              />
            </div>
          </div>

          <button 
            type="submit"
            className="w-full bg-primary text-white py-5 rounded-2xl font-black text-xl hover:bg-primary-hover hover:scale-[1.01] active:scale-[0.99] transition-all shadow-xl shadow-primary/20"
          >
            Post Listing Now
          </button>
        </form>
      </div>
    </div>
  );
}

export default AddFoodPage;
